mapper.select:
SELECT R.ITEMCODE, R.ITEMNAME, R.CHILDCODE, R.CHILDNAME, R.PRODQTY, R.SENDINGQTY, R.QTYPER, R.NEED, R.NEEDSUM, R.WORKMOVEQTY, R.RECEIVINGQTY, NVL(L.CURRENT_STOCK, 0) AS CURRENT_STOCK FROM ( SELECT X.ITEMCODE, X.ITEMNAME, X.CHILDCODE, X.CHILDNAME, X.PRODQTY, X.SENDINGQTY, X.QTYPER, X.NEED, SUM(X.NEED) OVER (PARTITION BY X.CHILDCODE) AS NEEDSUM, X.WORKMOVEQTY, X.RECEIVINGQTY FROM ( SELECT T.ITEMCODE, T.ITEMNAME, T.CHILDCODE, T.CHILDNAME, T.QTYPER, SUM(T.PRODQTY) AS PRODQTY, SUM(T.SENDINGQTY) AS SENDINGQTY, SUM(T.NEED) AS NEED, SUM(T.WORKMOVEQTY) AS WORKMOVEQTY, SUM(T.RECEIVINGQTY) AS RECEIVINGQTY FROM ( /* 1. 반제품 생산 + 소요량 */ SELECT A.ITEMCODE, B.ITEMNAME, C.CHILDCODE, D.ITEMNAME AS CHILDNAME, C.QTYPER, SUM(A.QTY) AS PRODQTY, 0 AS SENDINGQTY, SUM(A.QTY * C.QTYPER) AS NEED, 0 AS WORKMOVEQTY, 0 AS RECEIVINGQTY FROM T_WMS_SEMIWORK A INNER JOIN T_MI_ITEM B ON A.ITEMCODE = B.ITEMCODE LEFT JOIN T_MI_MBOMSTR C ON A.ITEMCODE = C.ITEMCODE AND C.CHILDCODE LIKE 'W100%' LEFT JOIN T_MI_ITEM D ON C.CHILDCODE = D.ITEMCODE WHERE A.SDATE >= #{sdate} AND A.SDATE <= #{edate} AND A.USEYN = 'Y' GROUP BY A.ITEMCODE, B.ITEMNAME, C.CHILDCODE, D.ITEMNAME, C.QTYPER
UNION ALL
/* 3. 공장이송 (SENDING) */ SELECT F.ITEMCODE, B.ITEMNAME, C.CHILDCODE, D.ITEMNAME AS CHILDNAME, C.QTYPER, 0 AS PRODQTY, SUM(F.QTY) AS SENDINGQTY, 0 AS NEED, 0 AS WORKMOVEQTY, 0 AS RECEIVINGQTY FROM T_WMS_FACTORYMOVE F INNER JOIN T_MI_ITEM B ON F.ITEMCODE = B.ITEMCODE LEFT JOIN T_MI_MBOMSTR C ON B.ITEMCODE = C.ITEMCODE AND C.CHILDCODE LIKE 'W100%' LEFT JOIN T_MI_ITEM D ON C.CHILDCODE = D.ITEMCODE WHERE F.SOURCE = 'SENDING' AND F.SDATE >= #{sdate} AND F.SDATE <= #{edate}
AND F.FACTORY = #{factory}
GROUP BY F.ITEMCODE, B.ITEMNAME, C.CHILDCODE, D.ITEMNAME, C.QTYPER
UNION ALL
/* 4. 자재 입고 (RECEIVING) */ SELECT C.ITEMCODE, D.ITEMNAME, G.ITEMCODE AS CHILDCODE, B.ITEMNAME AS CHILDNAME, C.QTYPER, 0 AS PRODQTY, 0 AS SENDINGQTY, 0 AS NEED, 0 AS WORKMOVEQTY, SUM(G.QTY) AS RECEIVINGQTY FROM T_WMS_FACTORYMOVE G INNER JOIN T_MI_ITEM B ON G.ITEMCODE = B.ITEMCODE LEFT JOIN T_MI_MBOMSTR C ON B.ITEMCODE = C.CHILDCODE AND C.CHILDCODE LIKE 'W100%' LEFT JOIN T_MI_ITEM D ON C.ITEMCODE = D.ITEMCODE WHERE G.SOURCE = 'RECEIVING' AND G.SDATE >= #{sdate} AND G.SDATE <= #{edate}
AND G.FACTORY = #{factory}
GROUP BY C.ITEMCODE, D.ITEMNAME, G.ITEMCODE, B.ITEMNAME, C.QTYPER
UNION ALL
/* 5. 공정불출 (WIPINPUT) */ SELECT C.ITEMCODE, D.ITEMNAME, Z.ITEMCODE AS CHILDCODE, B.ITEMNAME AS CHILDNAME, C.QTYPER, 0 AS PRODQTY, 0 AS SENDINGQTY, 0 AS NEED, SUM(Z.QTY) AS WORKMOVEQTY, 0 AS RECEIVINGQTY FROM T_WMS_WORKMOVE Z INNER JOIN T_MI_ITEM B ON Z.ITEMCODE = B.ITEMCODE LEFT JOIN T_MI_MBOMSTR C ON B.ITEMCODE = C.CHILDCODE AND C.CHILDCODE LIKE 'W100%' LEFT JOIN T_MI_ITEM D ON C.ITEMCODE = D.ITEMCODE WHERE Z.SOURCE = 'WIPINPUT' AND Z.USEYN = 'Y' AND Z.INDATE >= #{sdate} AND Z.INDATE <= #{edate}
AND Z.FACTORY = #{factory}
GROUP BY C.ITEMCODE, D.ITEMNAME, Z.ITEMCODE, B.ITEMNAME, C.QTYPER ) T WHERE T.ITEMCODE IS NOT NULL AND T.CHILDCODE IS NOT NULL AND T.ITEMNAME IS NOT NULL AND T.CHILDNAME IS NOT NULL GROUP BY T.ITEMCODE, T.ITEMNAME, T.CHILDCODE, T.CHILDNAME, T.QTYPER ) X WHERE X.PRODQTY != 0 OR X.SENDINGQTY != 0 ) R LEFT JOIN ( SELECT ITEMCODE, SUM(NVL(QTY, 0)) AS CURRENT_STOCK FROM T_WMS_LOCATION
1 = 1
AND FACTORY = #{factory}
GROUP BY ITEMCODE ) L ON R.CHILDCODE = L.ITEMCODE ORDER BY R.CHILDCODE, R.ITEMCODE

SELECT A.OUTDATE AS YMD, COUNT(A.OUTDATE) AS CNT, SUM(A.QTY) AS TOTAL_QTY, SUM(A.QTY * B.UNITPRICE) AS TOTAL_AMT FROM T_WMS_OUTBOUND A LEFT JOIN T_MI_ITEM B0 ON B0.ITEMCODE = A.ITEMCODE LEFT JOIN T_MI_TYPESUB C ON C.SUBCODE = B0.CARNO AND C.TYPECODE = 'MI041' LEFT JOIN T_SCM_BARCODE D ON D.BARCODE = A.BARCODE INNER JOIN ( SELECT ITEMCODE, UNITPRICE, ROW_NUMBER() OVER ( PARTITION BY ITEMCODE ORDER BY CONDATE DESC ) AS RN FROM T_SM_SALECUSTPRICE ) B ON B.ITEMCODE = A.ITEMCODE AND B.RN = 1 WHERE A.OUTDATE >= #{dateFrom} AND A.OUTDATE < #{dateTo} AND A.SOURCE = 'LOAD' AND A.USEYN = 'Y'
AND C.SUBNAME_CH = #{sub}
AND A.CUSTNAME = #{sub}
GROUP BY A.OUTDATE ORDER BY A.OUTDATE
